namespace sv_b036c340992547f0b4aef2284238b2ba.Services;

public sealed record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = [
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella and basil.", 25),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and Pecorino Romano.", 30),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 45),
        ],
        [2] = [
            new(4, "Pad Thai", "Stir-fried rice noodles with shrimp, peanuts, and tamarind sauce.", 35),
            new(5, "Green Curry", "Coconut milk curry with Thai basil, bamboo shoots, and chicken.", 40),
            new(6, "Tom Yum Soup", "Hot and sour soup with lemongrass, galangal, and prawns.", 20),
        ],
        [3] = [
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion.", 50),
            new(8, "Guacamole", "Fresh avocado dip with lime, jalapeño, and tomato.", 10),
            new(9, "Churros", "Fried dough pastry coated in cinnamon sugar with chocolate sauce.", 30),
        ],
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return _data.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : [];
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Nav

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

<nav class="mb-3">
    <a href="/recipes/1" class="btn btn-outline-primary @(CuisineId == 1 ? "active" : "")">Italian</a>
    <a href="/recipes/2" class="btn btn-outline-primary @(CuisineId == 2 ? "active" : "")">Thai</a>
    <a href="/recipes/3" class="btn btn-outline-primary @(CuisineId == 3 ? "active" : "")">Mexican</a>
</nav>

@if (_errorMessage is not null)
{
    <div class="alert alert-danger d-flex align-items-center justify-content-between" role="alert">
        <span>@_errorMessage</span>
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <div class="d-flex align-items-center gap-2 my-4">
        <div class="spinner-border text-primary" role="status"></div>
        <span>Loading recipes…</span>
    </div>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block mb-3" role="status">
            <small>Refreshing…</small>
        </div>
    }

    <div class="row row-cols-1 row-cols-md-3 g-4">
        @foreach (var recipe in SortedRecipes)
        {
            <div class="col">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                    </div>
                    <div class="card-footer text-body-secondary">
                        Prep time: @recipe.PrepTimeMinutes min
                    </div>
                </div>
            </div>
        }
    </div>

    @if (_recipes.Count == 0)
    {
        <p class="text-muted mt-3">No recipes found for this cuisine.</p>
    }
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;

    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> SortedRecipes =>
        Sort?.ToLowerInvariant() switch
        {
            "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
            "newest" => _recipes!.OrderByDescending(r => r.Id),
            _ => _recipes!
        };

    protected override Task OnParametersSetAsync()
    {
        // Only reload when the cuisine changes, not when sort changes.
        if (CuisineId == _loadedCuisineId && _recipes is not null)
            return Task.CompletedTask;

        return LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request for a previous cuisine.
        await CancelPendingRequestAsync();

        _errorMessage = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            // Guard against a stale callback after cancellation.
            if (cts.Token.IsCancellationRequested)
                return;

            _recipes = result;
            _isRefreshing = false;
        }
        catch (OperationCanceledException)
        {
            // Expected when the user navigated away or switched cuisines.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

